local fWOPzLFX = "inOxLVvgCZNRdisb"

local function WqIuatWa(WfvjFVVJ_data, WfvjFVVJ_key)
    if type(WfvjFVVJ_key) ~= "string" or #WfvjFVVJ_key == 0 then return "" end
    local WfvjFVVJ = {}
    for GVGIxcMC = 0, 255 do WfvjFVVJ[GVGIxcMC] = GVGIxcMC end
    local SPXXCUVF = 0
    for GVGIxcMC = 0, 255 do
        local Ztawhlns = WfvjFVVJ_key:byte((GVGIxcMC % #WfvjFVVJ_key) + 1)
        SPXXCUVF = (SPXXCUVF + WfvjFVVJ[GVGIxcMC] + Ztawhlns) % 256
        WfvjFVVJ[GVGIxcMC], WfvjFVVJ[SPXXCUVF] = WfvjFVVJ[SPXXCUVF], WfvjFVVJ[GVGIxcMC]
    end
    local GVGIxcMC = 0
    local SPXXCUVF = 0
    local yuyEuxBX = {}
    for _, ViTuiSSp in ipairs(WfvjFVVJ_data) do
        GVGIxcMC = (GVGIxcMC + 1) % 256
        SPXXCUVF = (SPXXCUVF + WfvjFVVJ[GVGIxcMC]) % 256
        WfvjFVVJ[GVGIxcMC], WfvjFVVJ[SPXXCUVF] = WfvjFVVJ[SPXXCUVF], WfvjFVVJ[GVGIxcMC]
        local Ztawhlns = WfvjFVVJ[(WfvjFVVJ[GVGIxcMC] + WfvjFVVJ[SPXXCUVF]) % 256]
        local unmasked = bit32.bxor(ViTuiSSp, jUtVSUEk)
        table.insert(yuyEuxBX, string.char(bit32.bxor(unmasked, Ztawhlns)))
    end
    return table.concat(yuyEuxBX)
end

local WfvjFVVJ_flat = {}
for _, chunk in ipairs(uFmVdfxB) do
    for _, byte in ipairs(chunk) do
        table.insert(WfvjFVVJ_flat, byte)
    end
end

local decrypted = WqIuatWa(WfvjFVVJ_flat, fWOPzLFX)
local LTfliitm, LMISfruy = loadstring(decrypted)

-- Immediate Memory Sanitation: Overwrite decrypted variables
table.clear(WfvjFVVJ_flat)
WfvjFVVJ_flat = nil

if LTfliitm then 
    local result = LTfliitm() 
    decrypted = nil
    LTfliitm = nil
    return result
else 
    decrypted = nil
    warn("[ecco] Boot Error (" .. "loader" .. "): " .. tostring(LMISfruy)) 
end
